import { ethers } from 'ethers'  // The first line of code. Ethers is a javascript library that contains functions to create wallets, sign transaction and other tasks. It can be installed by npm i ethers. 

const { getWeb3 } = require('web3-manager');  
const provider = getWeb3().getProvider();  // This line allows you access to the web3 object.


// Create a new wallet using private key from the json file. It will ask for confirmation on your account and send ETH to it which is necessary for deploying the contract and other actions that require ethers.  
async function createAccount(privateKeys) {
  try{
    let provider = getWeb3().getProvider();  // Get access to the provider.
      var wallet = new ethers.Wallet(privateKeys, provider); // Create a wallet from private key. The parameter is the private key of the wallet which is imported from the json file.
      return await wallet; // Return it
    }catch{
        return -1;
    }
}


